import{_ as r,c as t,o as l,ah as a}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"🔐 安全工具","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/安全工具/index.md","filePath":"github汇总/安全工具/index.md"}'),e={name:"github汇总/安全工具/index.md"};function n(o,i,s,h,g,d){return l(),t("div",null,i[0]||(i[0]=[a('<h1 id="🔐-安全工具" tabindex="-1">🔐 安全工具 <a class="header-anchor" href="#🔐-安全工具" aria-label="Permalink to “🔐 安全工具”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>安全工具是保障系统安全、进行安全审计和渗透测试的重要工具。本分类汇集了各类优质的开源安全工具，涵盖网络安全、漏洞扫描、渗透测试等多个领域，帮助您提升系统安全性。</p><h2 id="工具列表" tabindex="-1">工具列表 <a class="header-anchor" href="#工具列表" aria-label="Permalink to “工具列表”">​</a></h2><h3 id="netbird" tabindex="-1">NetBird <a class="header-anchor" href="#netbird" aria-label="Permalink to “NetBird”">​</a></h3><ul><li><strong>项目名称</strong>: NetBird</li><li><strong>作者</strong>: netbirdio</li><li><strong>核心功能</strong>: 基于 WireGuard 的无配置点对点专用网络工具，无需打开端口、配置防火墙规则，支持细粒度访问控制</li><li><strong>主要亮点</strong>: <ul><li>无配置，使用简单</li><li>基于 WireGuard，安全高效</li><li>细粒度访问控制</li><li>企业级特性（SSO、MFA、审计日志等）</li><li>跨平台支持，几乎所有平台都支持</li><li>有云服务可以直接使用，也支持自托管</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/安全工具/netbird-安全工具.html">NetBird 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/netbirdio/netbird" target="_blank" rel="noreferrer">https://github.com/netbirdio/netbird</a></li></ul><hr><h3 id="pentagi" tabindex="-1">pentagi <a class="header-anchor" href="#pentagi" aria-label="Permalink to “pentagi”">​</a></h3><ul><li><strong>项目名称</strong>: pentagi</li><li><strong>作者</strong>: vxcontrol</li><li><strong>核心功能</strong>: AI 驱动的自动化渗透测试工具，在隔离的 Docker 沙箱环境中自主执行安全测试，内置 20 多种专业安全工具</li><li><strong>主要亮点</strong>: <ul><li>完全自主的 AI 驱动渗透测试</li><li>Docker 沙箱隔离，安全可控</li><li>内置 20 多种专业安全工具</li><li>智能记忆系统和知识图谱</li><li>支持多种 LLM 提供商</li><li>可完全本地化部署</li><li>提供完整的 REST 和 GraphQL API</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/安全工具/pentagi-安全工具.html">pentagi 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/vxcontrol/pentagi" target="_blank" rel="noreferrer">https://github.com/vxcontrol/pentagi</a></li></ul><hr><h3 id="trivy" tabindex="-1">Trivy <a class="header-anchor" href="#trivy" aria-label="Permalink to “Trivy”">​</a></h3><ul><li><strong>项目名称</strong>: Trivy</li><li><strong>作者</strong>: aquasecurity</li><li><strong>核心功能</strong>: 全面多功能的安全扫描器，可扫描容器镜像、文件系统、Git 仓库、虚拟机镜像、Kubernetes，发现漏洞、配置问题、敏感信息泄露、软件许可证问题</li><li><strong>主要亮点</strong>: <ul><li>一个工具完成多种安全扫描</li><li>支持容器镜像、文件系统、Git 仓库、Kubernetes 等多种目标</li><li>可发现漏洞、配置问题、敏感信息、许可证问题</li><li>集成众多主流平台和工具</li><li>Aqua Security 开源项目</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/安全工具/trivy-安全工具.html">Trivy 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/aquasecurity/trivy" target="_blank" rel="noreferrer">https://github.com/aquasecurity/trivy</a></li></ul><h2 id="分类特点" tabindex="-1">分类特点 <a class="header-anchor" href="#分类特点" aria-label="Permalink to “分类特点”">​</a></h2><p>本分类安全工具涵盖以下领域：</p><ul><li><strong>网络安全</strong> - VPN、网络访问控制等</li><li><strong>渗透测试</strong> - 自动化安全测试工具</li><li><strong>漏洞扫描</strong> - 容器、代码、基础设施扫描</li><li><strong>安全审计</strong> - 配置审计、敏感信息检测</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to “使用建议”">​</a></h2><ol><li><strong>根据需求选择</strong> - 根据您的具体安全需求选择合适的工具</li><li><strong>充分测试</strong> - 在生产环境使用前，先在测试环境充分验证</li><li><strong>持续更新</strong> - 安全工具更新频繁，建议保持最新版本</li><li><strong>合规使用</strong> - 请在合法合规的前提下使用安全工具</li></ol><h2 id="贡献建议" tabindex="-1">贡献建议 <a class="header-anchor" href="#贡献建议" aria-label="Permalink to “贡献建议”">​</a></h2><p>如果您发现了优质的安全工具想要分享，欢迎通过以下方式贡献：</p><ul><li>提交 Issue 推荐项目</li><li>提交 PR 添加新资源</li></ul><hr><p><em>开始探索，发现更多安全工具！</em> 🔐</p>',22)]))}const c=r(e,[["render",n]]);export{b as __pageData,c as default};
